#include <iostream>
#include <algorithm>
using namespace std;
int n,a[200000],s[200000],c[200000],l,r,b[200000];
int fun(int x)
{
    for(int i=1;i<=x;i++)
    {
        b[i]=s[i];
    }
    sort(b+1,b+1+x);
    return b[1];
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        for(int j=n;j>=i;j--)
        {
            s[j]+=a[i];
        }
    }
    for(r=1;r<=n;r++)
    {
        int k=fun(r-1);
        c[r]=s[r]-k;
    }
    sort(c+1,c+n+1,greater<int>());
    cout<<c[1];
    return 0;
}
